from ldap3 import Server, Connection

LDAP_URI = 'ldaps://your-ldap-server.com'
BASE_DN = 'dc=example,dc=com'
USERNAME = 'username'

def search_user(username):
    server = Server(LDAP_URI)
    connection = Connection(server, user=USERNAME, password='password')
    connection.bind()

    search_query = f"({ldap.MOD_DN}=*)"
    search_filter = f"(&(objectClass=inetOrgPerson)(|(sAMAccountName={username})))"

    results = connection.search(BASE_DN, search_query, search_filter)

    return results[0] if results else None